import time

# CoAP Constants
COAP_VERSION = 1
COAP_PORT = 5683

# CoAP Types
CON = 0  # Confirmable
NON = 1  # Non-confirmable
ACK = 2  # Acknowledgement
RST = 3  # Reset

# CoAP Methods
EMPTY = 0
GET = 1
POST = 2
PUT = 3
DELETE = 4

# CoAP Response Codes
CREATED = (2, 1)
DELETED = (2, 2)
VALID = (2, 3)
CHANGED = (2, 4)
CONTENT = (2, 5)
BAD_REQUEST = (4, 0)
NOT_FOUND = (4, 4)
METHOD_NOT_ALLOWED = (4, 5)
INTERNAL_ERROR = (5, 0)

# Content Format
TEXT_PLAIN = 0
APP_JSON = 50


class CoapOption:
    def __init__(self, number, value=b''):
        self.number = number
        self.value = value


class CoapMessage:
    def __init__(self):
        self.version = COAP_VERSION
        self.type = CON
        self.token_length = 0
        self.code_class = 0
        self.code_detail = 0
        self.message_id = 0
        self.token = b''
        self.options = []
        self.payload = b''

    @property
    def uri_path(self):
        """Extract URI path from options (option number 11)."""
        parts = []
        for opt in self.options:
            if opt.number == 11:
                parts.append(opt.value.decode('utf-8'))
        return '/' + '/'.join(parts) if parts else '/'

    def encode(self):
        """Encode CoAP message to bytes."""
        buf = bytearray()

        # Header: 4 bytes
        byte0 = (self.version << 6) | (self.type << 4) | (self.token_length & 0x0F)
        code = ((self.code_class & 0x07) << 5) | (self.code_detail & 0x1F)
        buf.append(byte0)
        buf.append(code)
        buf.append((self.message_id >> 8) & 0xFF)
        buf.append(self.message_id & 0xFF)

        # Token
        if self.token:
            buf.extend(self.token)

        # Options (sorted by number)
        self.options.sort(key=lambda o: o.number)
        prev_number = 0
        for opt in self.options:
            delta = opt.number - prev_number
            length = len(opt.value)

            # Encode delta
            if delta < 13:
                d = delta
                d_ext = b''
            elif delta < 269:
                d = 13
                d_ext = bytes([delta - 13])
            else:
                d = 14
                d_ext = struct.pack('!H', delta - 269)

            # Encode length
            if length < 13:
                l = length
                l_ext = b''
            elif length < 269:
                l = 13
                l_ext = bytes([length - 13])
            else:
                l = 14
                l_ext = struct.pack('!H', length - 269)

            buf.append((d << 4) | l)
            buf.extend(d_ext)
            buf.extend(l_ext)
            buf.extend(opt.value)

            prev_number = opt.number

        # Payload marker + payload
        if self.payload:
            buf.append(0xFF)
            buf.extend(self.payload)

        return bytes(buf)

    @staticmethod
    def decode(data):
        """Decode bytes to CoAP message."""
        msg = CoapMessage()
        if len(data) < 4:
            return None

        byte0 = data[0]
        msg.version = (byte0 >> 6) & 0x03
        msg.type = (byte0 >> 4) & 0x03
        msg.token_length = byte0 & 0x0F

        code = data[1]
        msg.code_class = (code >> 5) & 0x07
        msg.code_detail = code & 0x1F

        msg.message_id = (data[2] << 8) | data[3]

        idx = 4

        # Token
        if msg.token_length > 0:
            msg.token = data[idx:idx + msg.token_length]
            idx += msg.token_length

        # Options
        prev_number = 0
        while idx < len(data):
            if data[idx] == 0xFF:
                idx += 1
                break

            byte = data[idx]
            idx += 1
            delta = (byte >> 4) & 0x0F
            length = byte & 0x0F

            if delta == 13:
                delta = data[idx] + 13
                idx += 1
            elif delta == 14:
                delta = struct.unpack('!H', data[idx:idx + 2])[0] + 269
                idx += 2

            if length == 13:
                length = data[idx] + 13
                idx += 1
            elif length == 14:
                length = struct.unpack('!H', data[idx:idx + 2])[0] + 269
                idx += 2

            opt_number = prev_number + delta
            opt_value = data[idx:idx + length]
            idx += length

            msg.options.append(CoapOption(opt_number, opt_value))
            prev_number = opt_number

        # Payload
        if idx < len(data):
            msg.payload = data[idx:]

        return msg


class DeviceState:
    """Manages device sensor readings and actuator states."""

    def __init__(self):
        self.light_state = False
        self.light_brightness = 0
        self._temp_pin = None
        self._setup_hardware()

    def _setup_hardware(self):
        """Initialize hardware peripherals."""
        try:
            # Try to set up ADC for temperature sensor (e.g., on GPIO 36 for ESP32)
            self._temp_pin = machine.ADC(machine.Pin(36))
            self._temp_pin.atten(machine.ADC.ATTN_11DB)
        except Exception:
            self._temp_pin = None

        try:
            # LED/Light actuator on GPIO 2 (built-in LED on many ESP32 boards)
            self._light_pin = machine.Pin(2, machine.Pin.OUT)
        except Exception:
            self._light_pin = None

    def read_temperature(self):
        """Read temperature from sensor. Returns dict with temp data."""
        if self._temp_pin:
            raw = self._temp_pin.read()
            # Simple conversion: adjust based on your sensor (e.g., LM35, thermistor)
            voltage = raw * 3.3 / 4095
            temp_c = voltage * 100  # LM35: 10mV per degree C
        else:
            # Simulated temperature for testing
            temp_c = 22.5 + (time.ticks_ms() % 100) / 50.0

        return {
            'temperature': round(temp_c, 2),
            'unit': 'celsius',
            'timestamp': time.time()
        }

    def get_light_state(self):
        """Get current light/actuator state."""
        return {
            'on': self.light_state,
            'brightness': self.light_brightness
        }

    def set_light_state(self, on=None, brightness=None):
        """Set light/actuator state."""
        if on is not None:
            self.light_state = bool(on)
        if brightness is not None:
            self.light_brightness = max(0, min(100, int(brightness)))

        # Drive hardware
        if self._light_pin:
            self._light_pin.value(1 if self.light_state else 0)

        return self.get_light_state()


class CoapResource:
    """Represents a CoAP resource with handlers."""

    def __init__(self, path, get_handler=None, put_handler=None):
        self.path = path
        self.get_handler = get_handler
        self.put_handler = put_handler


class CoapServer:
    """Lightweight CoAP server for MicroPython IoT devices."""

    def __init__(self, host='0.0.0.0', port=COAP_PORT):
        self.host = host
        self.port = port
        self.resources = {}
        self.sock = None
        self.running = False
        self._msg_id_counter = 0

    def add_resource(self, path, get_handler=None, put_handler=None):
        """Register a resource with its handlers."""
        self.resources[path] = CoapResource(path, get_handler, put_handler)
        print("[CoAP] Resource registered: {}".format(path))

    def _next_msg_id(self):
        self._msg_id_counter = (self._msg_id_counter + 1) & 0xFFFF
        return self._msg_id_counter

    def _build_response(self, request, code, payload=b'', content_format=APP_JSON):
        """Build a CoAP response message."""
        resp = CoapMessage()
        resp.version = COAP_VERSION

        # ACK for CON, NON for NON
        if request.type == CON:
            resp.type = ACK
        else:
            resp.type = NON

        resp.code_class = code[0]
        resp.code_detail = code[1]
        resp.message_id = request.message_id
        resp.token = request.token
        resp.token_length = len(request.token)

        # Add content format option (option 12)
        if payload:
            resp.options.append(CoapOption(12, struct.pack('!B', content_format)))
            if isinstance(payload, str):
                payload = payload.encode('utf-8')
            resp.payload = payload

        return resp

    def _handle_request(self, data, addr):
        """Process incoming CoAP request and return response bytes."""
        msg = CoapMessage.decode(data)
        if msg is None:
            return None

        uri = msg.uri_path
        method = msg.code_detail  # For class 0, detail is the method

        print("[CoAP] {} {} from {}".format(
            {GET: 'GET', PUT: 'PUT', POST: 'POST', DELETE: 'DELETE'}.get(method, '?'),
            uri, addr
        ))

        # Look up resource
        resource = self.resources.get(uri)

        if resource is None:
            resp = self._build_response(msg, NOT_FOUND, json.dumps({'error': 'not found'}))
            return resp.encode()

        try:
            if method == GET:
                if resource.get_handler:
                    result = resource.get_handler()
                    payload = json.dumps(result)
                    resp = self._build_response(msg, CONTENT, payload)
                else:
                    resp = self._build_response(msg, METHOD_NOT_ALLOWED,
                                                json.dumps({'error': 'GET not allowed'}))

            elif method == PUT:
                if resource.put_handler:
                    # Parse incoming payload
                    req_payload = {}
                    if msg.payload:
                        try:
                            req_payload = json.loads(msg.payload.decode('utf-8'))
                        except (ValueError, UnicodeError):
                            resp = self._build_response(msg, BAD_REQUEST,
                                                        json.dumps({'error': 'invalid JSON'}))
                            return resp.encode()

                    result = resource.put_handler(req_payload)
                    payload = json.dumps(result)
                    resp = self._build_response(msg, CHANGED, payload)
                else:
                    resp = self._build_response(msg, METHOD_NOT_ALLOWED,
                                                json.dumps({'error': 'PUT not allowed'}))
            else:
                resp = self._build_response(msg, METHOD_NOT_ALLOWED,
                                            json.dumps({'error': 'method not supported'}))

        except Exception as e:
            print("[CoAP] Handler error: {}".format(e))
            resp = self._build_response(msg, INTERNAL_ERROR,
                                        json.dumps({'error': str(e)}))

        return resp.encode()

    def start(self):
        """Start the CoAP server (blocking)."""
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.sock.bind((self.host, self.port))
        self.sock.settimeout(1.0)  # Allow periodic checks

        self.running = True
        print("[CoAP] Server listening on {}:{}".format(self.host, self.port))
        print("[CoAP] Resources: {}".format(list(self.resources.keys())))

        while self.running:
            try:
                data, addr = self.sock.recvfrom(1024)
                if data:
                    response = self._handle_request(data, addr)
                    if response:
                        self.sock.sendto(response, addr)
            except OSError:
                # Timeout - continue loop
                pass
            except KeyboardInterrupt:
                print("\n[CoAP] Shutting down...")
                self.running = False

        self.sock.close()
        print("[CoAP] Server stopped")

    def stop(self):
        """Stop the server."""
        self.running = False


class WellKnownCoreHandler:
    """Handles /.well-known/core for CoAP resource discovery."""

    def __init__(self, server):
        self.server = server

    def get(self):
        """Return resource directory in CoRE Link Format."""
        links = []
        for path, resource in self.server.resources.items():
            if path == '/.well-known/core':
                continue
            methods = []
            if resource.get_handler:
                methods.append('GET')
            if resource.put_handler:
                methods.append('PUT')
            link = '<{}>;ct=50;methods="{}"'.format(path, ','.join(methods))
            links.append(link)
        # Return as plain text link format
        return ','.join(links)


def connect_wifi(ssid, password, timeout=15):
    """Connect to WiFi network."""
    import network
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)

    if wlan.isconnected():
        print("[WiFi] Already connected: {}".format(wlan.ifconfig()[0]))
        return wlan.ifconfig()[0]

    print("[WiFi] Connecting to {}...".format(ssid))
    wlan.connect(ssid, password)

    start = time.time()
    while not wlan.isconnected():
        if time.time() - start > timeout:
            raise RuntimeError("WiFi connection timeout")
        time.sleep(0.5)

    ip = wlan.ifconfig()[0]
    print("[WiFi] Connected: {}".format(ip))
    return ip


def main():
    """Main entry point - set up and run CoAP server."""

    # -- WiFi Configuration --
    # Uncomment and configure for your network:
    # connect_wifi('YOUR_SSID', 'YOUR_PASSWORD')

    # Initialize device state manager
    device = DeviceState()

    # Create CoAP server
    server = CoapServer(host='0.0.0.0', port=5683)

    # --- Resource Handlers ---

    # Temperature sensor resource (GET only)
    def temp_get():
        return device.read_temperature()

    # Light actuator resource (GET and PUT)
    def light_get():
        return device.get_light_state()

    def light_put(payload):
        """
        Accepts JSON payload like:
        {"on": true, "brightness": 75}
        """
        on = payload.get('on', None)
        brightness = payload.get('brightness', None)
        return device.set_light_state(on=on, brightness=brightness)

    # Device info resource (GET only)
    def device_info_get():
        try:
            import os
            uname = os.uname()
            platform = uname.sysname
            version = uname.version
        except Exception:
            platform = 'unknown'
            version = 'unknown'

        return {
            'device': 'iot-node',
            'platform': platform,
            'firmware': version,
            'uptime_ms': time.ticks_ms(),
            'free_mem': getattr(machine, 'mem_free', lambda: -1)() if hasattr(machine, 'mem_free') else -1
        }

    # --- Register Resources ---
    server.add_resource('/sensors/temp', get_handler=temp_get)
    server.add_resource('/actuators/light', get_handler=light_get, put_handler=light_put)
    server.add_resource('/device/info', get_handler=device_info_get)

    # Resource discovery
    discovery = WellKnownCoreHandler(server)
    server.add_resource('/.well-known/core', get_handler=discovery.get)

    # --- Start Server ---
    print("=" * 50)
    print("CoAP IoT Server")
    print("=" * 50)
    print("Resources:")
    print("  GET  /sensors/temp       - Read temperature")
    print("  GET  /actuators/light    - Get light state")
    print("  PUT  /actuators/light    - Set light state")
    print("       payload: {\"on\": true, \"brightness\": 75}")
    print("  GET  /device/info        - Device information")
    print("  GET  /.well-known/core   - Resource discovery")
    print("=" * 50)
    print()
    print("Test with: coap-client -m get coap://<IP>/sensors/temp")
    print("           coap-client -m put -e '{\"on\":true}' coap://<IP>/actuators/light")
    print()

    server.start()


# Run the server
if __name__ == '__main__':
    main()